/* global console, process */
import { spawn } from 'node:child_process';
import { existsSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import path from 'node:path';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const gnosisDir = path.resolve(__dirname, '../..');
const monsterPath = path.resolve(gnosisDir, 'polyglot/target/release/monster');
const gnexecPath = path.resolve(gnosisDir, 'polyglot/target/release/gnexec');
const monsterRuntimePath = existsSync(monsterPath) ? monsterPath : gnexecPath;

if (!existsSync(monsterRuntimePath)) {
  console.error(`Monster runtime not found at ${monsterRuntimePath}`);
  process.exit(1);
}

async function runSingleRequest(userId, naive = false) {
  return new Promise((resolve, reject) => {
    const child = spawn(monsterRuntimePath, [
      '--resident-jsonl',
      path.resolve(__dirname, 'fanout.ts'),
    ], {
      env: { ...process.env, ...(naive ? { FOIL_NAIVE: '1' } : {}) },
      stdio: ['pipe', 'pipe', 'pipe'],
    });

    let output = '';

    child.stdout.setEncoding('utf8');
    child.stdout.on('data', (chunk) => {
      output += chunk;
    });

    child.on('close', (code) => {
      try {
        const line = output.trim();
        const result = JSON.parse(line);
        if (result.ok) {
          resolve(result.elapsed_ns);
        } else {
          reject(new Error(result.error));
        }
      } catch (e) {
        reject(e);
      }
    });

    child.on('error', reject);

    const input = JSON.stringify({ userId });
    child.stdin.write(input + '\n');
    child.stdin.end();
  });
}

async function main() {
  console.log('🔥 FOIL Optimization Direct Comparison');
  console.log('════════════════════════════════════════════════════════════════\n');
  console.log('Single-request latency: FOIL_NAIVE vs OPTIMIZED\n');

  const runs = 50;
  const naiveLatencies = [];
  const optimizedLatencies = [];
  const testUser = 'benchmark-user-001';

  console.log(`Running ${runs} requests each...\n`);

  // FOIL_NAIVE runs
  process.stdout.write('FOIL_NAIVE:   ');
  for (let i = 0; i < runs; i++) {
    try {
      const latency = await runSingleRequest(testUser, true);
      naiveLatencies.push(latency / 1000); // Convert to µs
      process.stdout.write('.');
    } catch (e) {
      console.error(`Error: ${e.message}`);
      process.exit(1);
    }
  }
  console.log(' done\n');

  // OPTIMIZED runs
  process.stdout.write('OPTIMIZED:    ');
  for (let i = 0; i < runs; i++) {
    try {
      const latency = await runSingleRequest(testUser, false);
      optimizedLatencies.push(latency / 1000); // Convert to µs
      process.stdout.write('.');
    } catch (e) {
      console.error(`Error: ${e.message}`);
      process.exit(1);
    }
  }
  console.log(' done\n');

  // Analysis
  const naiveSorted = naiveLatencies.sort((a, b) => a - b);
  const optimizedSorted = optimizedLatencies.sort((a, b) => a - b);

  function stats(arr) {
    const sum = arr.reduce((a, b) => a + b, 0);
    const mean = sum / arr.length;
    const p50 = arr[Math.floor(arr.length * 0.50)];
    const p95 = arr[Math.floor(arr.length * 0.95)];
    const p99 = arr[Math.floor(arr.length * 0.99)];
    const max = arr[arr.length - 1];
    const min = arr[0];
    return { mean, p50, p95, p99, max, min };
  }

  const naiveStats = stats(naiveSorted);
  const optimizedStats = stats(optimizedSorted);

  console.log('════════════════════════════════════════════════════════════════');
  console.log('FOIL_NAIVE Baseline');
  console.log('════════════════════════════════════════════════════════════════');
  console.log(`  min:  ${naiveStats.min.toFixed(1)} µs`);
  console.log(`  p50:  ${naiveStats.p50.toFixed(1)} µs`);
  console.log(`  p95:  ${naiveStats.p95.toFixed(1)} µs`);
  console.log(`  p99:  ${naiveStats.p99.toFixed(1)} µs`);
  console.log(`  max:  ${naiveStats.max.toFixed(1)} µs`);
  console.log(`  mean: ${naiveStats.mean.toFixed(1)} µs`);

  console.log('\n════════════════════════════════════════════════════════════════');
  console.log('OPTIMIZED (FOIL enhancements)');
  console.log('════════════════════════════════════════════════════════════════');
  console.log(`  min:  ${optimizedStats.min.toFixed(1)} µs`);
  console.log(`  p50:  ${optimizedStats.p50.toFixed(1)} µs`);
  console.log(`  p95:  ${optimizedStats.p95.toFixed(1)} µs`);
  console.log(`  p99:  ${optimizedStats.p99.toFixed(1)} µs`);
  console.log(`  max:  ${optimizedStats.max.toFixed(1)} µs`);
  console.log(`  mean: ${optimizedStats.mean.toFixed(1)} µs`);

  console.log('\n════════════════════════════════════════════════════════════════');
  console.log('FOIL Optimization Gains');
  console.log('════════════════════════════════════════════════════════════════');

  const improvements = {
    min: ((naiveStats.min - optimizedStats.min) / naiveStats.min) * 100,
    p50: ((naiveStats.p50 - optimizedStats.p50) / naiveStats.p50) * 100,
    p95: ((naiveStats.p95 - optimizedStats.p95) / naiveStats.p95) * 100,
    p99: ((naiveStats.p99 - optimizedStats.p99) / naiveStats.p99) * 100,
    mean: ((naiveStats.mean - optimizedStats.mean) / naiveStats.mean) * 100,
  };

  const speedups = {
    min: naiveStats.min / optimizedStats.min,
    p50: naiveStats.p50 / optimizedStats.p50,
    p95: naiveStats.p95 / optimizedStats.p95,
    p99: naiveStats.p99 / optimizedStats.p99,
    mean: naiveStats.mean / optimizedStats.mean,
  };

  console.log(`\n  p50 improvement:  ${improvements.p50.toFixed(1)}% faster (${speedups.p50.toFixed(2)}×)`);
  console.log(`  p95 improvement:  ${improvements.p95.toFixed(1)}% faster (${speedups.p95.toFixed(2)}×)`);
  console.log(`  p99 improvement:  ${improvements.p99.toFixed(1)}% faster (${speedups.p99.toFixed(2)}×)`);
  console.log(`  mean improvement: ${improvements.mean.toFixed(1)}% faster (${speedups.mean.toFixed(2)}×)`);

  const overallGain = (improvements.p99 + improvements.mean) / 2;
  console.log(`\n  ✓ FOIL optimizations delivered ${overallGain.toFixed(1)}% latency reduction`);

  process.exit(0);
}

main().catch(e => {
  console.error('Error:', e.message);
  process.exit(1);
});
